import json


def extract_resource_logical_ids(template_str: str) -> list[str]:
    """
    Parse an AWS CloudFormation template in JSON format and extract all resource logical IDs.

    Args:
        template_str: A string containing a valid JSON CloudFormation template.

    Returns:
        A list of strings representing the logical IDs of all resources defined
        in the 'Resources' section of the template.

    Raises:
        TypeError: If template_str is not a str (checked via isinstance).
        ValueError: If the JSON is malformed and cannot be parsed.
        ValueError: If the parsed JSON root is not a dict.
        ValueError: If the parsed dict does not contain a 'Resources' key.
        ValueError: If the value of 'Resources' is not a dict.
        ValueError: If the 'Resources' dict is empty.
        ValueError: If any key in the 'Resources' dict is not a string.
    """
    if not isinstance(template_str, str):
        raise TypeError(
            f"Expected type 'str', got '{type(template_str).__name__}'"
        )

    try:
        parsed = json.loads(template_str)
    except json.JSONDecodeError as e:
        raise ValueError(f"Failed to parse JSON template: {e}") from e

    if not isinstance(parsed, dict):
        raise ValueError(
            f"Expected the root of the template to be a dict, got '{type(parsed).__name__}'"
        )

    if "Resources" not in parsed:
        raise ValueError("Template is missing the required top-level 'Resources' key")

    resources = parsed["Resources"]

    if not isinstance(resources, dict):
        raise ValueError(
            f"Expected 'Resources' to be a dict, got '{type(resources).__name__}'"
        )

    if len(resources) == 0:
        raise ValueError("'Resources' dict must not be empty")

    for key in resources:
        if not isinstance(key, str):
            raise ValueError(
                f"All keys in 'Resources' must be strings, found non-string key: {key!r}"
            )

    return list(resources.keys())

import re
import unittest

ARN_PATTERN = re.compile(
    r'^(?P<partition>arn:aws|arn:aws-us-gov|arn:aws-cn):iam::(?P<account_id>\d{12}):role/(?P<role_name>[a-zA-Z0-9_\-]+(/[a-zA-Z0-9_\-]+)*)$'
)

def match_arn(arn):
    if not isinstance(arn, str) or not arn:
        return None
    return ARN_PATTERN.match(arn)

class TestARN(unittest.TestCase):
    def test_standard_aws(self):
        m = match_arn('arn:aws:iam::123456789012:role/MyRole')
        self.assertIsNotNone(m)
        self.assertEqual(m.group('partition'), 'arn:aws')
        self.assertEqual(m.group('account_id'), '123456789012')
        self.assertEqual(m.group('role_name'), 'MyRole')

    def test_govcloud(self):
        m = match_arn('arn:aws-us-gov:iam::123456789012:role/GovRole')
        self.assertIsNotNone(m)
        self.assertEqual(m.group('partition'), 'arn:aws-us-gov')

    def test_china(self):
        m = match_arn('arn:aws-cn:iam::123456789012:role/CnRole')
        self.assertIsNotNone(m)
        self.assertEqual(m.group('partition'), 'arn:aws-cn')

    def test_invalid_arn(self):
        self.assertIsNone(match_arn('arn:azure:iam::123456789012:role/MyRole'))

    def test_none_input(self):
        self.assertIsNone(match_arn(None))

    def test_empty_string(self):
        self.assertIsNone(match_arn(''))

    def test_consecutive_slashes(self):
        self.assertIsNone(match_arn('arn:aws:iam::123456789012:role/path//role'))

    def test_path_with_single_slash(self):
        m = match_arn('arn:aws:iam::123456789012:role/path/role-name')
        self.assertIsNotNone(m)
        self.assertEqual(m.group('role_name'), 'path/role-name')

if __name__ == '__main__':
    unittest.main()

import json
from typing import Union


def flatten_metadata(data: Union[dict, str], prefix: str = '', _depth: int = 0) -> dict:
    """
    Convert AWS EC2 instance metadata JSON response into a flattened dictionary with dot-notation keys.

    Ordering of checks (applied at every recursive call):
      1. Depth guard: if _depth >= 20, raise RecursionError immediately, before any type validation or parsing.
      2. Type validation: if data is None or not a dict or str, raise TypeError.
      3. JSON parsing: if data is a str, parse it with json.loads(); raise ValueError for invalid JSON,
         or TypeError if the parsed result is not a dict.

    Design decision: List values are not recursively flattened with numeric indices. If a JSON array
    appears as a leaf value, it is stored as-is (the entire list object) under its dot-notation key.
    This is intentional and must not silently attempt partial list flattening.

    Parameters:
        data (Union[dict, str]): The input metadata, either a pre-parsed dict or a raw JSON string.
        prefix (str): The dot-notation prefix accumulated during recursion. Default is ''.
        _depth (int): Internal recursion depth counter. Default is 0. Used to enforce a maximum
            recursion depth of 19 (depth 20 is the first disallowed level, i.e., _depth >= 20
            raises RecursionError). Do not pass this parameter manually.

    Returns:
        dict: A flat dictionary where all nested keys are joined with dot-notation and leaf values
            are preserved as-is (including lists).

    Raises:
        RecursionError: If _depth >= 20, raised before any other check.
        TypeError: If data is None or not a dict or str (at any recursive call), or if a JSON string
            parses to a non-dict type (message explicitly states the original input was a JSON string
            whose parsed result was not a dict).
        ValueError: If data is a string but not valid JSON.

    Example:
        >>> metadata = {
        ...     "instanceId": "i-1234567890abcdef0",
        ...     "network": {
        ...         "interfaces": {
        ...             "0": {"mac": "02:42:ac:11:00:02"}
        ...         }
        ...     }
        ... }
        >>> flatten_metadata(metadata)
        {'instanceId': 'i-1234567890abcdef0', 'network.interfaces.0.mac': '02:42:ac:11:00:02'}
    """
    if _depth >= 20:
        raise RecursionError(f"Maximum recursion depth of 19 exceeded at depth {_depth}.")
    if data is None or not isinstance(data, (dict, str)):
        raise TypeError(f"Expected dict or str, got {type(data).__name__}.")
    if isinstance(data, str):
        try:
            parsed = json.loads(data)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON string: {e}") from e
        if not isinstance(parsed, dict):
            raise TypeError(f"JSON string parsed to {type(parsed).__name__}, expected dict.")
        data = parsed
    result = {}
    for key, value in data.items():
        full_key = f"{prefix}.{key}" if prefix else key
        if isinstance(value, dict):
            result.update(flatten_metadata(value, full_key, _depth + 1))
        else:
            result[full_key] = value
    return result
